create table dirkspzm32.lvs_packschema_kopf (
    sid                 varchar2(2 char) not null enable,
    firma_nr            number(2, 0) not null enable,
    packschema_kopf_id  varchar2(20 char) not null enable,
    text                varchar2(80 char),
    anz_lagen           number(*, 0) default 1 not null enable,
    gerade_lagen_drehen varchar2(1 char) default 'F' not null enable,
    basis_lte_name      varchar2(22 char) not null enable,
    lhm_name            varchar2(50 char) not null enable,
    x_ueberstand_max    number(*, 5) default 0 not null enable,
    y_ueberstand_max    number(*, 5) default 0 not null enable,
    create_date         date,
    create_login_id     number(*, 0),
    change_date         date,
    change_login_id     number(*, 0),
    min_anz_lhm         number(*, 0),
    lte_name            varchar2(22 char),
    lte_host_anz        number(*, 0) default 1,
    prozess_param       varchar2(50 char),
    wickelprogramm      varchar2(4 char),
    max_gesamt_hoehe_mm number(*, 3),
    aufstapel_kopf_list varchar2(200 char)
);

alter table dirkspzm32.lvs_packschema_kopf
    add constraint pk_lvs_packschema_kopf
        primary key ( packschema_kopf_id,
                      firma_nr,
                      sid )
            using index enable;


